const data     = $input.first().json;
const queryDate = $('ET 날짜 계산').first().json.query_date;
const games    = [];

for (const dateEntry of (data.dates || [])) {
  for (const game of (dateEntry.games || [])) {
    if (game.status?.abstractGameState === 'Final') continue;

    const venueId  = game.venue?.id;
    const stadium  = STADIUMS[venueId] ?? { name: game.venue?.name ?? 'Unknown', lat: null, lng: null, dome: false };

    games.push({
      game_pk:          game.gamePk,
      game_date:        dateEntry.date,
      game_datetime:    game.gameDate,
      home_team_id:     game.teams?.home?.team?.id,
      home_team:        game.teams?.home?.team?.name,
      away_team_id:     game.teams?.away?.team?.id,
      away_team:        game.teams?.away?.team?.name,
      status:           game.status?.detailedState,
      home_pitcher_id:  game.teams?.home?.probablePitcher?.id ?? null,
      away_pitcher_id:  game.teams?.away?.probablePitcher?.id ?? null,
      venue_id:         venueId,
      venue_name:       stadium.name,
      venue_lat:        stadium.lat,
      venue_lng:        stadium.lng,
      venue_dome:       stadium.dome
    });
  }
}

if (games.length === 0) {
  return [{ json: { skipped: true, reason: '오늘 예정 경기 없음', date: queryDate } }];
}

console.log(`오늘 경기 ${games.length}개 발견`);
return games.map(g => ({ json: g }));

// 선수 ID 추출 (투수/포수/야수/타선)
const boxscore = $input.first().json;
const gameInfo = $('경기 목록 파싱 + 구장 매핑').item.json;

const result = [];

for (const side of ['home', 'away']) {
  const team = boxscore.teams?.[side];
  if (!team) continue;

  const pitcherIds        = team.pitchers || [];
  const startingPitcherId = pitcherIds[0] ?? gameInfo[`${side === 'home' ? 'home' : 'away'}_pitcher_id`];
  if (!startingPitcherId) continue;

  let   catcherId  = null;
  const fielderIds = [];
  const batterIds  = [];

  for (const playerId of (team.battingOrder || [])) {
    const player  = team.players?.[`ID${playerId}`];
    const posCode = player?.position?.code;
    const batSide = player?.batSide?.code ?? 'R';

    batterIds.push({
      batter_id:   playerId,
      batter_name: player?.person?.fullName ?? '',
      bat_side:    batSide,
      position:    player?.position?.abbreviation ?? ''
    });

    if (posCode === '2') catcherId = playerId;
    const posNum = parseInt(posCode);
    if (posNum >= 3 && posNum <= 9) fielderIds.push(playerId);
  }

  result.push({
    json: {
      game_pk:          gameInfo.game_pk,
      game_date:        gameInfo.game_date,
      game_datetime:    gameInfo.game_datetime,
      side:             side,
      pitcher_id:       startingPitcherId,
      catcher_id:       catcherId,
      fielder_ids:      fielderIds,
      batter_ids:       batterIds,
      venue_name:       gameInfo.venue_name,
      venue_lat:        gameInfo.venue_lat,
      venue_lng:        gameInfo.venue_lng,
      venue_dome:       gameInfo.venue_dome,
      home_team:        gameInfo.home_team,
      away_team:        gameInfo.away_team
    }
  });
}

return result;

// 돔 구장 기본 날씨값 설정
const gameInfo = $input.first().json;
return [{
  json: {
    ...gameInfo,
    weather: {
      temperature:              22,
      humidity:                 50,
      windSpeed:                0,
      windDirection:            0,
      precipitationProbability: 0,
      dome:                     true
    }
  }
}];

// 날씨 응답 정규화
const gameInfo = $('선수 ID 추출').item.json;
const weatherRaw = $input.first().json;

const values = weatherRaw?.data?.values ?? {};

return [{
  json: {
    ...gameInfo,
    weather: {
      temperature:              values.temperature              ?? null,
      humidity:                 values.humidity                 ?? null,
      windSpeed:                values.windSpeed                ?? null,
      windDirection:            values.windDirection            ?? null,
      precipitationProbability: values.precipitationProbability ?? null,
      dome:                     false
    }
  }
}];

// 타선 vs 선발 투수 상대전적 + 최근 성적 병렬 수집 준비
// 타선 배열을 개별 item으로 분리
const gameInfo = $('선수 ID 추출').item.json;
const batters  = gameInfo.batter_ids || [];

if (batters.length === 0) {
  return [{ json: { ...gameInfo, batter_stats_ready: false } }];
}

// 각 타자를 독립 item으로 → 다음 노드에서 병렬 API 호출
return batters.map(b => ({
  json: {
    game_pk:     gameInfo.game_pk,
    pitcher_id:  gameInfo.pitcher_id,
    batter_id:   b.batter_id,
    batter_name: b.batter_name,
    bat_side:    b.bat_side,
    // 컨텍스트 전달용
    game_context: {
      game_pk:      gameInfo.game_pk,
      game_date:    gameInfo.game_date,
      side:         gameInfo.side,
      home_team:    gameInfo.home_team,
      away_team:    gameInfo.away_team,
      venue_name:   gameInfo.venue_name,
      venue_dome:   gameInfo.venue_dome,
      weather:      gameInfo.weather,
      pitcher_id:   gameInfo.pitcher_id,
      catcher_id:   gameInfo.catcher_id,
      fielder_ids:  gameInfo.fielder_ids,
      batter_ids:   gameInfo.batter_ids
    }
  }
}));

// 타자별 최근 성적 + 상대전적 집계
const recentItems = $('타자 최근 7일 성적').all();
const vsItems = [];
const batterItems = $('타선 분리').all();

// 선수 ID 추출에서 game_context 가져오기
const playerData  = $('선수 ID 추출').first().json;

const gameContext = {
  game_pk:      playerData.game_pk,
  game_date:    playerData.game_date,
  game_datetime: playerData.game_datetime,
  side:         playerData.side,
  home_team:    playerData.home_team,
  away_team:    playerData.away_team,
  venue_name:   playerData.venue_name,
  venue_dome:   playerData.venue_dome,
  weather:      playerData.weather ?? {},
  pitcher_id:   playerData.pitcher_id,
  catcher_id:   playerData.catcher_id,
  fielder_ids:  playerData.fielder_ids,
  batter_ids:   playerData.batter_ids
};

// 타자 ID 기준으로 성적 매핑
const batterProfiles = [];

for (let i = 0; i < batterItems.length; i++) {
  const batter = batterItems[i].json;
  const recent = recentItems[i]?.json ?? {};
  const vs     = vsItems[i]?.json ?? {};

  const recentStat = recent.stats?.[0]?.splits?.[0]?.stat ?? {};
  const vsStat     = vs.stats?.[0]?.splits?.[0]?.stat ?? {};

  batterProfiles.push({
    batter_id:   batter.batter_id,
    batter_name: batter.batter_name,
    bat_side:    batter.bat_side,
    recent_7days: {
      avg:        recentStat.avg        ?? '.000',
      ops:        recentStat.ops        ?? '.000',
      hits:       recentStat.hits       ?? 0,
      homeRuns:   recentStat.homeRuns   ?? 0,
      strikeOuts: recentStat.strikeOuts ?? 0,
      gamesPlayed: recentStat.gamesPlayed ?? 0
    },
    vs_pitcher: {
      avg:        vsStat.avg        ?? '.000',
      atBats:     vsStat.atBats     ?? 0,
      hits:       vsStat.hits       ?? 0,
      homeRuns:   vsStat.homeRuns   ?? 0,
      strikeOuts: vsStat.strikeOuts ?? 0
    }
  });
}

return [{
  json: {
    game_pk:         gameContext.game_pk,
    game_context:    gameContext,
    batter_profiles: batterProfiles
  }
}];

const aggregate = $('타자 데이터 집계').item.json;
const aiRaw = $input.first().json.output ?? '{}';

let aiAnalysis;
try {
  aiAnalysis = JSON.parse(aiRaw);
} catch (e) {
  aiAnalysis = { context_summary: aiRaw, weather_impact: '', key_matchups: [], hot_batters: [], cold_batters: [], recommended_focus: '' };
}

const context = {
  game_pk:         aggregate.game_pk,
  game_date:       aggregate.game_context?.game_date,
  game_datetime:   aggregate.game_context?.game_datetime,
  home_team:       aggregate.game_context?.home_team,
  away_team:       aggregate.game_context?.away_team,
  venue_name:      aggregate.game_context?.venue_name,
  venue_dome:      aggregate.game_context?.venue_dome,
  weather:         aggregate.game_context?.weather,
  pitcher_id:      aggregate.game_context?.pitcher_id,
  catcher_id:      aggregate.game_context?.catcher_id,
  fielder_ids:     aggregate.game_context?.fielder_ids,
  batter_profiles: aggregate.batter_profiles,
  ai_analysis:     aiAnalysis,
  created_at:      new Date().toISOString()
};

// fs 대신 Static Data에 저장
const staticData = $getWorkflowStaticData('global');
staticData[`context_${context.game_pk}`] = context;

console.log(`컨텍스트 저장 완료: game_pk=${context.game_pk}`);

return [{ json: { success: true, game_pk: context.game_pk, context } }];
